import java.util.*;

public class Main {
    public static long solve(long n, long[][] edges) {
        Map<Long, List<long[]>> graph = new HashMap<>();
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long start = edge[2];
            long end = edge[3];
            graph.computeIfAbsent(u, k -> new ArrayList<>()).add(new long[]{v, start, end});
        }

        PriorityQueue<long[]> heap = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        heap.offer(new long[]{0, 0});
        Map<Long, Long> visited = new HashMap<>();
        visited.put(0L, 0L);

        while (!heap.isEmpty()) {
            long[] current = heap.poll();
            long currentTime = current[0];
            long node = current[1];
            if (node == n - 1) {
                return currentTime;
            }
            if (currentTime > visited.getOrDefault(node, Long.MAX_VALUE)) {
                continue;
            }
            // Option 1: Stay at current node (wait for 1 unit)
            long newTime = currentTime + 1;
            if (newTime < visited.getOrDefault(node, Long.MAX_VALUE)) {
                visited.put(node, newTime);
                heap.offer(new long[]{newTime, node});
            }
            // Option 2: Try to use outgoing edges
            if (graph.containsKey(node)) {
                for (long[] edge : graph.get(node)) {
                    long neighbor = edge[0];
                    long start = edge[1];
                    long end = edge[2];
                    long t = Math.max(currentTime, start);
                    if (t <= end) {
                        long arrivalTime = t + 1;
                        if (arrivalTime < visited.getOrDefault(neighbor, Long.MAX_VALUE)) {
                            visited.put(neighbor, arrivalTime);
                            heap.offer(new long[]{arrivalTime, neighbor});
                        }
                    }
                }
            }
        }
        return -1;
    }
}
